#include <stdio.h>
#include <stdlib.h>

int merge(int* nums, int left, int mid, int right) {
    int count = 0;
    int* temp = (int*)malloc((right - left + 1) * sizeof(int));
    int i = left, j = mid + 1, k = 0;
    while (i <= mid && j <= right) {
        if (nums[i] > 2 * nums[j]) {
            count += mid - i + 1;
            temp[k++] = nums[j];
            j++;
        } else {
            temp[k++] = nums[i];
            i++;
        }
    }
    while (i <= mid) {
        temp[k++] = nums[i];
        i++;
    }
    while (j <= right) {
        temp[k++] = nums[j];
        j++;
    }
    for (i = left, k = 0; i <= right; i++, k++) {
        nums[i] = temp[k];
    }
    free(temp);
    return count;
}

int reversePairs(int* nums, int left, int right) {
    int count = 0;
    if (left < right) {
        int mid = left + (right - left) / 2;
        count += reversePairs(nums, left, mid);
        count += reversePairs(nums, mid + 1, right);
        count += merge(nums, left, mid, right);
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* nums = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &nums[i]);
        }
        printf("%d\n", reversePairs(nums, 0, N - 1));
        free(nums);
    }
    return 0;
}

